// testMultiDeviceU2FChallenge verifies that when multiple U2F devices are registered,
// the authentication challenge includes challenges for all devices, not just one.
func testMultiDeviceU2FChallenge(t *testing.T) {
	ctx := context.Background()
	clock := clockwork.NewFakeClock()
	as, err := auth.NewTestAuthServer(auth.TestAuthServerConfig{
		Dir:   t.TempDir(),
		Clock: clock,
	})
	require.NoError(t, err)
	defer as.Close()

	// Enable U2F support
	authPref, err := services.NewAuthPreference(types.AuthPreferenceSpecV2{
		Type: teleport.Local,
		U2F: &types.U2F{
			AppID:  "teleport",
			Facets: []string{"teleport"},
		},
	})
	require.NoError(t, err)
	err = as.AuthServer.SetAuthPreference(authPref)
	require.NoError(t, err)

	// Create a test user
	user, _, err := auth.CreateUserAndRole(as.AuthServer, "test-user", []string{"role"})
	require.NoError(t, err)

	// Register multiple U2F devices
	u2fDevices := make(map[string]*mocku2f.Key)
	deviceNames := []string{"device-1", "device-2", "device-3"}

	for _, deviceName := range deviceNames {
		mockDev, err := mocku2f.Create()
		require.NoError(t, err)
		u2fDevices[deviceName] = mockDev

		// Register the device
		regChallenge, err := as.AuthServer.CreateRegisterChallenge(ctx, user.GetName(), proto.MFARegisterChallengeRequest_U2F)
		require.NoError(t, err)

		u2fRegChallenge := regChallenge.GetU2F()
		require.NotNil(t, u2fRegChallenge, "U2F challenge should not be nil")

		// Generate registration response
		regResp, err := mockDev.RegisterResponse(&u2f.RegisterChallenge{
			Challenge: u2fRegChallenge.Challenge,
			AppID:     u2fRegChallenge.AppID,
		})
		require.NoError(t, err)

		// Complete the registration
		_, err = as.AuthServer.AddMFADeviceSync(ctx, user.GetName(), deviceName, &proto.MFARegisterResponse{
			Response: &proto.MFARegisterResponse_U2F{U2F: &proto.U2FRegisterResponse{
				RegistrationData: regResp.RegistrationData,
				ClientData:       regResp.ClientData,
			}},
		})
		require.NoError(t, err)
	}

	// Now get the authentication challenge - this should include challenges for ALL devices
	// BUG: Currently this might only return a challenge for the first device
	u2fStorage, err := u2f.InMemoryAuthenticationStorage(as.AuthServer.Services)
	require.NoError(t, err)

	authChallenge, err := as.AuthServer.mfaAuthChallenge(ctx, user.GetName(), u2fStorage)
	require.NoError(t, err)

	// CRITICAL TEST: The bug manifests here - authChallenge.U2F should have 3 challenges,
	// but the buggy code might only return 1
	if len(authChallenge.U2F) != len(deviceNames) {
		t.Errorf("REGRESSION BUG: Expected %d U2F challenges for %d registered devices, but got %d. "+
			"This indicates the multi-device U2F authentication bug where only one device's "+
			"challenge is presented instead of all devices.",
			len(deviceNames), len(deviceNames), len(authChallenge.U2F))
	}
	require.Equal(t, len(deviceNames), len(authChallenge.U2F),
		"Expected all registered U2F devices to have challenges in the authentication request")

	// Verify each challenge corresponds to a registered device
	seenKeyHandles := make(map[string]bool)
	expectedKeyHandles := make(map[string]bool)
	for _, dev := range u2fDevices {
		kh := base64.URLEncoding.WithPadding(base64.NoPadding).EncodeToString(dev.KeyHandle)
		expectedKeyHandles[kh] = true
	}

	for _, challenge := range authChallenge.U2F {
		require.NotEmpty(t, challenge.KeyHandle, "Challenge should have a KeyHandle")
		require.NotEmpty(t, challenge.Challenge, "Challenge should have Challenge data")
		require.NotEmpty(t, challenge.AppID, "Challenge should have AppID")
		seenKeyHandles[challenge.KeyHandle] = true
	}

	// Verify that all expected key handles are present
	require.Equal(t, expectedKeyHandles, seenKeyHandles,
		"All registered device key handles should appear in authentication challenges")
}

// testMultiDeviceU2FAuthentication verifies that each registered device can authenticate
// independently and the correct device is identified from the response.
func testMultiDeviceU2FAuthentication(t *testing.T) {
	ctx := context.Background()
	clock := clockwork.NewFakeClock()
	as, err := auth.NewTestAuthServer(auth.TestAuthServerConfig{
		Dir:   t.TempDir(),
		Clock: clock,
	})
	require.NoError(t, err)
	defer as.Close()

	// Enable U2F support
	authPref, err := services.NewAuthPreference(types.AuthPreferenceSpecV2{
		Type: teleport.Local,
		U2F: &types.U2F{
			AppID:  "teleport",
			Facets: []string{"teleport"},
		},
	})
	require.NoError(t, err)
	err = as.AuthServer.SetAuthPreference(authPref)
	require.NoError(t, err)

	// Create a test user
	user, _, err := auth.CreateUserAndRole(as.AuthServer, "test-user-2", []string{"role"})
	require.NoError(t, err)

	// Register multiple U2F devices
	u2fDevices := make(map[string]*mocku2f.Key)
	deviceNames := []string{"device-a", "device-b", "device-c"}

	for _, deviceName := range deviceNames {
		mockDev, err := mocku2f.Create()
		require.NoError(t, err)
		u2fDevices[deviceName] = mockDev

		// Register the device
		regChallenge, err := as.AuthServer.CreateRegisterChallenge(ctx, user.GetName(), proto.MFARegisterChallengeRequest_U2F)
		require.NoError(t, err)

		u2fRegChallenge := regChallenge.GetU2F()
		require.NotNil(t, u2fRegChallenge)

		// Generate registration response
		regResp, err := mockDev.RegisterResponse(&u2f.RegisterChallenge{
			Challenge: u2fRegChallenge.Challenge,
			AppID:     u2fRegChallenge.AppID,
		})
		require.NoError(t, err)

		// Complete the registration
		_, err = as.AuthServer.AddMFADeviceSync(ctx, user.GetName(), deviceName, &proto.MFARegisterResponse{
			Response: &proto.MFARegisterResponse_U2F{U2F: &proto.U2FRegisterResponse{
				RegistrationData: regResp.RegistrationData,
				ClientData:       regResp.ClientData,
			}},
		})
		require.NoError(t, err)
	}

	// Get authentication challenge
	u2fStorage, err := u2f.InMemoryAuthenticationStorage(as.AuthServer.Services)
	require.NoError(t, err)

	authChallenge, err := as.AuthServer.mfaAuthChallenge(ctx, user.GetName(), u2fStorage)
	require.NoError(t, err)

	require.Equal(t, len(deviceNames), len(authChallenge.U2F),
		"Expected all registered U2F devices to have challenges")

	// Test that we can authenticate with each device
	// For each device, simulate a tap and verify authentication succeeds
	for _, challenge := range authChallenge.U2F {
		// Find which mock device corresponds to this challenge
		var matchingMockDev *mocku2f.Key
		for _, mockDev := range u2fDevices {
			kh := base64.URLEncoding.WithPadding(base64.NoPadding).EncodeToString(mockDev.KeyHandle)
			if kh == challenge.KeyHandle {
				matchingMockDev = mockDev
				break
			}
		}
		require.NotNil(t, matchingMockDev, "Should find mock device for challenge")

		// Generate signature using this device
		signResp, err := matchingMockDev.SignResponse(&u2f.AuthenticateChallenge{
			Challenge: challenge.Challenge,
			KeyHandle: challenge.KeyHandle,
			AppID:     challenge.AppID,
		})
		require.NoError(t, err)

		// Verify the signature on the server side
		// BUG: If multiple devices send responses, the server might not correctly
		// identify which device was used
		err = as.AuthServer.CheckU2FSignResponse(ctx, user.GetName(), &u2f.AuthenticateChallengeResponse{
			KeyHandle:     signResp.KeyHandle,
			ClientData:    signResp.ClientData,
			SignatureData: signResp.SignatureData,
		})
		if err != nil {
			t.Errorf("REGRESSION BUG: Authentication failed for device with KeyHandle %s. "+
				"This could indicate a bug in multi-device challenge verification where "+
				"the server fails to match the response to the correct device.",
				challenge.KeyHandle)
		}
		require.NoError(t, err, "Authentication with registered device should succeed")
	}
}

// testMultiDeviceChallengeSeparation verifies that challenges are properly isolated
// between different devices and don't interfere with each other during verification.
func testMultiDeviceChallengeSeparation(t *testing.T) {
	ctx := context.Background()
	clock := clockwork.NewFakeClock()
	as, err := auth.NewTestAuthServer(auth.TestAuthServerConfig{
		Dir:   t.TempDir(),
		Clock: clock,
	})
	require.NoError(t, err)
	defer as.Close()

	// Enable U2F support
	authPref, err := services.NewAuthPreference(types.AuthPreferenceSpecV2{
		Type: teleport.Local,
		U2F: &types.U2F{
			AppID:  "teleport",
			Facets: []string{"teleport"},
		},
	})
	require.NoError(t, err)
	err = as.AuthServer.SetAuthPreference(authPref)
	require.NoError(t, err)

	// Create a test user
	user, _, err := auth.CreateUserAndRole(as.AuthServer, "test-user-3", []string{"role"})
	require.NoError(t, err)

	// Register two devices
	device1, err := mocku2f.Create()
	require.NoError(t, err)
	device2, err := mocku2f.Create()
	require.NoError(t, err)

	// Register device 1
	regChallenge1, err := as.AuthServer.CreateRegisterChallenge(ctx, user.GetName(), proto.MFARegisterChallengeRequest_U2F)
	require.NoError(t, err)
	regResp1, err := device1.RegisterResponse(&u2f.RegisterChallenge{
		Challenge: regChallenge1.GetU2F().Challenge,
		AppID:     regChallenge1.GetU2F().AppID,
	})
	require.NoError(t, err)
	_, err = as.AuthServer.AddMFADeviceSync(ctx, user.GetName(), "device-1", &proto.MFARegisterResponse{
		Response: &proto.MFARegisterResponse_U2F{U2F: &proto.U2FRegisterResponse{
			RegistrationData: regResp1.RegistrationData,
			ClientData:       regResp1.ClientData,
		}},
	})
	require.NoError(t, err)

	// Register device 2
	regChallenge2, err := as.AuthServer.CreateRegisterChallenge(ctx, user.GetName(), proto.MFARegisterChallengeRequest_U2F)
	require.NoError(t, err)
	regResp2, err := device2.RegisterResponse(&u2f.RegisterChallenge{
		Challenge: regChallenge2.GetU2F().Challenge,
		AppID:     regChallenge2.GetU2F().AppID,
	})
	require.NoError(t, err)
	_, err = as.AuthServer.AddMFADeviceSync(ctx, user.GetName(), "device-2", &proto.MFARegisterResponse{
		Response: &proto.MFARegisterResponse_U2F{U2F: &proto.U2FRegisterResponse{
			RegistrationData: regResp2.RegistrationData,
			ClientData:       regResp2.ClientData,
		}},
	})
	require.NoError(t, err)

	// Get first authentication challenge
	u2fStorage, err := u2f.InMemoryAuthenticationStorage(as.AuthServer.Services)
	require.NoError(t, err)

	authChallenge1, err := as.AuthServer.mfaAuthChallenge(ctx, user.GetName(), u2fStorage)
	require.NoError(t, err)
	require.Equal(t, 2, len(authChallenge1.U2F), "Should have 2 challenges")

	// Extract challenges for each device
	var chal1, chal2 *proto.U2FChallenge
	kh1 := base64.URLEncoding.WithPadding(base64.NoPadding).EncodeToString(device1.KeyHandle)
	kh2 := base64.URLEncoding.WithPadding(base64.NoPadding).EncodeToString(device2.KeyHandle)

	for _, chal := range authChallenge1.U2F {
		if chal.KeyHandle == kh1 {
			chal1 = chal
		} else if chal.KeyHandle == kh2 {
			chal2 = chal
		}
	}
	require.NotNil(t, chal1, "Should find challenge for device 1")
	require.NotNil(t, chal2, "Should find challenge for device 2")

	// Verify challenges are different (they should be, generated independently)
	if chal1.Challenge == chal2.Challenge {
		// This is actually acceptable - challenges can theoretically be the same
		// but key handles must be different
		t.Logf("Note: Challenges happen to be the same (OK)")
	}
	require.NotEqual(t, chal1.KeyHandle, chal2.KeyHandle,
		"Key handles for different devices must be unique")

	// Verify that device 1 cannot authenticate with device 2's challenge
	// This is a critical security test
	wrongSignResp, err := device1.SignResponse(&u2f.AuthenticateChallenge{
		Challenge: chal2.Challenge,
		KeyHandle: chal2.KeyHandle,
		AppID:     chal2.AppID,
	})
	require.NoError(t, err)

	// Attempting to authenticate device 1 with device 2's challenge should fail
	err = as.AuthServer.CheckU2FSignResponse(ctx, user.GetName(), &u2f.AuthenticateChallengeResponse{
		KeyHandle:     wrongSignResp.KeyHandle,
		ClientData:    wrongSignResp.ClientData,
		SignatureData: wrongSignResp.SignatureData,
	})
	if err == nil {
		t.Error("REGRESSION BUG: Device 1 was able to authenticate with device 2's challenge. " +
			"This indicates a critical security issue in multi-device U2F authentication where " +
			"challenges are not properly isolated between devices.")
	}
	require.Error(t, err, "Using wrong device for challenge should fail")

	// Now verify that each device CAN authenticate with its own challenge
	correctSignResp1, err := device1.SignResponse(&u2f.AuthenticateChallenge{
		Challenge: chal1.Challenge,
		KeyHandle: chal1.KeyHandle,
		AppID:     chal1.AppID,
	})
	require.NoError(t, err)

	err = as.AuthServer.CheckU2FSignResponse(ctx, user.GetName(), &u2f.AuthenticateChallengeResponse{
		KeyHandle:     correctSignResp1.KeyHandle,
		ClientData:    correctSignResp1.ClientData,
		SignatureData: correctSignResp1.SignatureData,
	})
	require.NoError(t, err, "Device 1 should authenticate with its own challenge")

	// Create a fresh challenge set for device 2 to authenticate
	authChallenge2, err := as.AuthServer.mfaAuthChallenge(ctx, user.GetName(), u2fStorage)
	require.NoError(t, err)

	var chal2Fresh *proto.U2FChallenge
	for _, chal := range authChallenge2.U2F {
		if chal.KeyHandle == kh2 {
			chal2Fresh = chal
			break
		}
	}
	require.NotNil(t, chal2Fresh, "Should find fresh challenge for device 2")

	correctSignResp2, err := device2.SignResponse(&u2f.AuthenticateChallenge{
		Challenge: chal2Fresh.Challenge,
		KeyHandle: chal2Fresh.KeyHandle,
		AppID:     chal2Fresh.AppID,
	})
	require.NoError(t, err)

	err = as.AuthServer.CheckU2FSignResponse(ctx, user.GetName(), &u2f.AuthenticateChallengeResponse{
		KeyHandle:     correctSignResp2.KeyHandle,
		ClientData:    correctSignResp2.ClientData,
		SignatureData: correctSignResp2.SignatureData,
	})
	require.NoError(t, err, "Device 2 should authenticate with its own challenge")
}

// Utility function to close the test auth server
func (a *auth.TestAuthServer) Close() error {
	if a.AuthServer != nil {
		a.AuthServer.Close()
	}
	return nil
}

