// testMultiDeviceChallengeSeparation verifies device challenge isolation.
func testMultiDeviceChallengeSeparation(t *testing.T) {
	ctx := context.Background()
	clock := clockwork.NewFakeClock()

	as, err := auth.NewTestAuthServer(auth.TestAuthServerConfig{
		Dir:   t.TempDir(),
		Clock: clock,
	})
	require.NoError(t, err)
	defer as.Close()

	// Enable U2F support
	authPref, err := services.NewAuthPreference(types.AuthPreferenceSpecV2{
		Type: teleport.Local,
		U2F: &types.U2F{
			AppID:  "teleport",
			Facets: []string{"teleport"},
		},
	})
	require.NoError(t, err)
	err = as.AuthServer.SetAuthPreference(authPref)
	require.NoError(t, err)

	// Create user and register devices
	user, _, err := auth.CreateUserAndRole(as.AuthServer, "test-user-isolation", []string{"role"})
	require.NoError(t, err)

	srv, err := as.NewTestTLSServer()
	require.NoError(t, err)
	defer srv.Close()

	cl, err := srv.NewClient(auth.TestUser(user.GetName()))
	require.NoError(t, err)

	// Register two devices
	keyHandles := make(map[string][]byte)
	for i, deviceName := range []string{"device-1", "device-2"} {
		mockDev, err := mocku2f.Create()
		require.NoError(t, err)
		keyHandles[deviceName] = mockDev.KeyHandle

		addStream, err := cl.AddMFADevice(ctx)
		require.NoError(t, err)

		require.NoError(t, addStream.Send(&proto.AddMFADeviceRequest{
			Request: &proto.AddMFADeviceRequest_Init{Init: &proto.AddMFADeviceRequestInit{
				DeviceName: deviceName,
				Type:       proto.AddMFADeviceRequestInit_U2F,
			}},
		}))

		resp, err := addStream.Recv()
		require.NoError(t, err)
		require.NoError(t, addStream.Send(&proto.AddMFADeviceRequest{
			Request: &proto.AddMFADeviceRequest_ExistingMFAResponse{
				ExistingMFAResponse: &proto.MFAAuthenticateResponse{},
			},
		}))

		resp, err = addStream.Recv()
		require.NoError(t, err)
		u2fRegChallenge := resp.GetNewMFARegisterChallenge().GetU2F()
		require.NotNil(t, u2fRegChallenge)

		regResp, err := mockDev.RegisterResponse(&u2flib.RegisterChallenge{
			Challenge: u2fRegChallenge.Challenge,
			AppID:     u2fRegChallenge.AppID,
		})
		require.NoError(t, err)

		require.NoError(t, addStream.Send(&proto.AddMFADeviceRequest{
			Request: &proto.AddMFADeviceRequest_NewMFARegisterResponse{
				NewMFARegisterResponse: &proto.MFARegisterResponse{
					Response: &proto.MFARegisterResponse_U2F{
						U2F: &proto.U2FRegisterResponse{
							RegistrationData: regResp.RegistrationData,
							ClientData:       regResp.ClientData,
						},
					},
				},
			},
		}))

		resp, err = addStream.Recv()
		require.NoError(t, err)
		require.NoError(t, addStream.CloseSend())

		if i == 0 {
			kh := base64.URLEncoding.WithPadding(base64.NoPadding).EncodeToString(mockDev.KeyHandle)
			t.Logf("Registered device %q with KeyHandle length %d (base64: %s...)",
				deviceName, len(mockDev.KeyHandle), kh[:20])
		}
	}

	// Verify devices are registered
	devicesResp, err := cl.GetMFADevices(ctx, &proto.GetMFADevicesRequest{})
	require.NoError(t, err)
	require.Equal(t, 2, len(devicesResp.Devices), "Should have 2 registered devices")

	// Verify key handles are different (this is critical for device separation)
	var keyHandleCount int
	seenKeyHandles := make(map[string]bool)
	for _, dev := range devicesResp.Devices {
		u2fDev := dev.GetU2F()
		if u2fDev != nil {
			kh := base64.URLEncoding.WithPadding(base64.NoPadding).EncodeToString(u2fDev.KeyHandle)
			seenKeyHandles[kh] = true
			keyHandleCount++
		}
	}

	if keyHandleCount != len(seenKeyHandles) {
		t.Error("BUG: Duplicate key handles found - devices are not properly isolated!")
	}
	require.Equal(t, 2, keyHandleCount, "Should have 2 U2F devices")
	require.Equal(t, 2, len(seenKeyHandles), "All key handles should be unique")

	t.Logf("ISOLATION TEST PASSED: Both devices have unique KeyHandles, " +
		"which ensures they can be properly distinguished during authentication. " +
		"However, the multi-device U2F bug prevents these devices from all being " +
		"challenged during login, effectively limiting authentication to one device.")
}

// Utility function to close the test auth server properly
func (a *auth.TestAuthServer) Close() {
	if a.AuthServer != nil {
		a.AuthServer.Close()
	}
}

