// TestRegression verifies that multi-device U2F authentication works correctly.
// This test addresses several issues with U2F authentication:
// 1. Multiple U2F devices should all present challenges during login
// 2. Each registered device should be able to authenticate independently
// 3. Device management operations should work correctly with multiple devices
// 4. Challenge generation and verification should maintain device-device isolation
func TestRegression(t *testing.T) {
	// Run all regression tests
	t.Run("MultiDeviceU2FChallenge", testMultiDeviceU2FChallenge)
	t.Run("MultiDeviceU2FAuthentication", testMultiDeviceU2FAuthentication)
	t.Run("MultiDeviceChallengeSeparation", testMultiDeviceChallengeSeparation)
}

// testMultiDeviceU2FChallenge verifies that when multiple U2F devices are registered,
// the authentication challenge includes challenges for all devices, not just one.
func testMultiDeviceU2FChallenge(t *testing.T) {
	ctx := context.Background()
	clock := clockwork.NewFakeClock()

	// Set up auth server with U2F enabled
	as, err := auth.NewTestAuthServer(auth.TestAuthServerConfig{
		Dir:   t.TempDir(),
		Clock: clock,
	})
	require.NoError(t, err)
	defer as.Close()

	srv, err := as.NewTestTLSServer()
	require.NoError(t, err)
	defer srv.Close()

	// Enable U2F support
	authPref, err := services.NewAuthPreference(types.AuthPreferenceSpecV2{
		Type: teleport.Local,
		U2F: &types.U2F{
			AppID:  "teleport",
			Facets: []string{"teleport"},
		},
	})
	require.NoError(t, err)
	err = as.AuthServer.SetAuthPreference(authPref)
	require.NoError(t, err)

	// Create a test user and add a TOTP device first (needed for auth challenges)
	user, _, err := auth.CreateUserAndRole(as.AuthServer, "test-user", []string{"role"})
	require.NoError(t, err)

	cl, err := srv.NewClient(auth.TestUser(user.GetName()))
	require.NoError(t, err)

	// Add a TOTP device first so we can authenticate when adding U2F devices
	addStream, err := cl.AddMFADevice(ctx)
	require.NoError(t, err)
	require.NoError(t, addStream.Send(&proto.AddMFADeviceRequest{
		Request: &proto.AddMFADeviceRequest_Init{Init: &proto.AddMFADeviceRequestInit{
			DeviceName: "totp-device",
			Type:       proto.AddMFADeviceRequestInit_TOTP,
		}},
	}))

	// Get the challenge (should be empty for first device)
	resp, err := addStream.Recv()
	require.NoError(t, err)
	authChallenge := resp.GetExistingMFAChallenge()
	require.NotNil(t, authChallenge)
	require.NoError(t, addStream.Send(&proto.AddMFADeviceRequest{
		Request: &proto.AddMFADeviceRequest_ExistingMFAResponse{
			ExistingMFAResponse: &proto.MFAAuthenticateResponse{},
		},
	}))

	// Get the registration challenge
	resp, err = addStream.Recv()
	require.NoError(t, err)
	totpChallenge := resp.GetNewMFARegisterChallenge().GetTOTP()
	require.NotNil(t, totpChallenge)

	// Generate TOTP code and complete registration
	code, err := totp.GenerateCodeCustom(
		totpChallenge.Secret,
		clock.Now(),
		totp.ValidateOpts{
			Period:    uint(totpChallenge.PeriodSeconds),
			Digits:    uint(totpChallenge.Digits),
			Algorithm: totpChallenge.Algorithm,
		},
	)
	require.NoError(t, err)

	require.NoError(t, addStream.Send(&proto.AddMFADeviceRequest{
		Request: &proto.AddMFADeviceRequest_NewMFARegisterResponse{
			NewMFARegisterResponse: &proto.MFARegisterResponse{
				Response: &proto.MFARegisterResponse_TOTP{
