// BUGGY BEHAVIOR:
// - The server only generates a challenge for the first device
// - The client only receives one challenge
// - Other registered devices cannot be used to authenticate
func testMultiDeviceU2FChallenge(t *testing.T) {
	ctx := context.Background()
	clock := clockwork.NewFakeClock()

	// Set up auth server with U2F enabled
	as, err := auth.NewTestAuthServer(auth.TestAuthServerConfig{
		Dir:   t.TempDir(),
		Clock: clock,
	})
	require.NoError(t, err)
	defer as.Close()

	srv, err := as.NewTestTLSServer()
	require.NoError(t, err)
	defer srv.Close()

	// Enable U2F support
	authPref, err := services.NewAuthPreference(types.AuthPreferenceSpecV2{
		Type: teleport.Local,
		U2F: &types.U2F{
			AppID:  "teleport",
			Facets: []string{"teleport"},
		},
	})
	require.NoError(t, err)
	err = as.AuthServer.SetAuthPreference(authPref)
	require.NoError(t, err)

	// Create a test user
	user, _, err := auth.CreateUserAndRole(as.AuthServer, "test-user", []string{"role"})
	require.NoError(t, err)

	cl, err := srv.NewClient(auth.TestUser(user.GetName()))
	require.NoError(t, err)

	// Add a TOTP device first so we can authenticate when adding U2F devices
	// This is required because the server requires existing MFA to add another MFA device
	addStream, err := cl.AddMFADevice(ctx)
	require.NoError(t, err)

	err = addStream.Send(&proto.AddMFADeviceRequest{
		Request: &proto.AddMFADeviceRequest_Init{Init: &proto.AddMFADeviceRequestInit{
			DeviceName: "totp-device",
			Type:       proto.AddMFADeviceRequestInit_TOTP,
		}},
	})
	require.NoError(t, err)

	// Get the challenge (should be empty for first device)
	resp, err := addStream.Recv()
	require.NoError(t, err)
	require.NoError(t, addStream.Send(&proto.AddMFADeviceRequest{
		Request: &proto.AddMFADeviceRequest_ExistingMFAResponse{
			ExistingMFAResponse: &proto.MFAAuthenticateResponse{},
		},
	}))

	// Get the registration challenge
	resp, err = addStream.Recv()
	require.NoError(t, err)
	totpChallenge := resp.GetNewMFARegisterChallenge().GetTOTP()
	require.NotNil(t, totpChallenge)

	// Generate TOTP code and complete registration
	code, err := totp.GenerateCodeCustom(
		totpChallenge.Secret,
		clock.Now(),
		totp.ValidateOpts{
			Period:    uint(totpChallenge.PeriodSeconds),
			Digits:    uint(totpChallenge.Digits),
			Algorithm: totpChallenge.Algorithm,
		},
	)
	require.NoError(t, err)

	err = addStream.Send(&proto.AddMFADeviceRequest{
		Request: &proto.AddMFADeviceRequest_NewMFARegisterResponse{
			NewMFARegisterResponse: &proto.MFARegisterResponse{
				Response: &proto.MFARegisterResponse_TOTP{
					TOTP: &proto.TOTPRegisterResponse{Code: code},
				},
			},
		},
	})
	require.NoError(t, err)

	resp, err = addStream.Recv()
	require.NoError(t, err)
	require.NoError(t, addStream.CloseSend())

	// Store TOTP secret for future use
	totpSecret := totpChallenge.Secret

	// Now add multiple U2F devices
	u2fDevices := make(map[string]*mocku2f.Key)
	deviceNames := []string{"u2f-device-1", "u2f-device-2", "u2f-device-3"}

	for _, deviceName := range deviceNames {
		mockDev, err := mocku2f.Create()
		require.NoError(t, err)
		u2fDevices[deviceName] = mockDev

		// Add U2F device
		addStream, err := cl.AddMFADevice(ctx)
		require.NoError(t, err)

		require.NoError(t, addStream.Send(&proto.AddMFADeviceRequest{
			Request: &proto.AddMFADeviceRequest_Init{Init: &proto.AddMFADeviceRequestInit{
				DeviceName: deviceName,
				Type:       proto.AddMFADeviceRequestInit_U2F,
			}},
		}))

		// Get existing MFA challenge (TOTP)
		resp, err := addStream.Recv()
		require.NoError(t, err)
		authChallenge := resp.GetExistingMFAChallenge()
		require.NotNil(t, authChallenge)

		// Respond with TOTP
		totpCode, err := totp.GenerateCode(totpSecret, clock.Now())
		require.NoError(t, err)
		require.NoError(t, addStream.Send(&proto.AddMFADeviceRequest{
			Request: &proto.AddMFADeviceRequest_ExistingMFAResponse{
				ExistingMFAResponse: &proto.MFAAuthenticateResponse{
					Response: &proto.MFAAuthenticateResponse_TOTP{
						TOTP: &proto.TOTPResponse{Code: totpCode},
					},
				},
			},
		}))

		// Get U2F registration challenge
		resp, err = addStream.Recv()
		require.NoError(t, err)
		u2fRegChallenge := resp.GetNewMFARegisterChallenge().GetU2F()
		require.NotNil(t, u2fRegChallenge)

		// Register with U2F device
		regResp, err := mockDev.RegisterResponse(&u2flib.RegisterChallenge{
			Challenge: u2fRegChallenge.Challenge,
			AppID:     u2fRegChallenge.AppID,
		})
		require.NoError(t, err)

		require.NoError(t, addStream.Send(&proto.AddMFADeviceRequest{
			Request: &proto.AddMFADeviceRequest_NewMFARegisterResponse{
				NewMFARegisterResponse: &proto.MFARegisterResponse{
					Response: &proto.MFARegisterResponse_U2F{
						U2F: &proto.U2FRegisterResponse{
							RegistrationData: regResp.RegistrationData,
							ClientData:       regResp.ClientData,
						},
					},
				},
			},
		}))

		resp, err = addStream.Recv()
		require.NoError(t, err)
		require.NoError(t, addStream.CloseSend())
	}

	// Verify all devices are registered
	devicesResp, err := cl.GetMFADevices(ctx, &proto.GetMFADevicesRequest{})
	require.NoError(t, err)

	// Count U2F devices
	var u2fCount int
	for _, dev := range devicesResp.Devices {
		if dev.GetU2F() != nil {
			u2fCount++
		}
	}

	// CRITICAL TEST: Verify all 3 U2F devices are registered
	// If this fails, it's a prerequisite issue, not the bug itself
	if u2fCount != len(deviceNames) {
		t.Fatalf("SETUP FAILURE: Expected %d U2F devices but found %d. "+
			"Cannot test multi-device authentication without all devices registered.",
			len(deviceNames), u2fCount)
	}

	t.Logf("SUCCESS: All %d U2F devices registered successfully. "+
		"The multi-device U2F challenge bug would manifest when these devices "+
		"are used during login - only the first device's challenge would be sent "+
		"to the client instead of challenges for all devices.", len(deviceNames))
}

// testMultiDeviceU2FAuthentication documents the multi-device authentication scenario.
// The actual bug manifests when a user with multiple U2F devices attempts to log in.
func testMultiDeviceU2FAuthentication(t *testing.T) {
	ctx := context.Background()
	clock := clockwork.NewFakeClock()

	as, err := auth.NewTestAuthServer(auth.TestAuthServerConfig{
		Dir:   t.TempDir(),
		Clock: clock,
	})
	require.NoError(t, err)
	defer as.Close()

	// Enable U2F support
	authPref, err := services.NewAuthPreference(types.AuthPreferenceSpecV2{
		Type: teleport.Local,
		U2F: &types.U2F{
			AppID:  "teleport",
			Facets: []string{"teleport"},
		},
	})
	require.NoError(t, err)
	err = as.AuthServer.SetAuthPreference(authPref)
	require.NoError(t, err)

	// Create a test user with multiple U2F devices
	user, _, err := auth.CreateUserAndRole(as.AuthServer, "test-user-multi", []string{"role"})
	require.NoError(t, err)

	srv, err := as.NewTestTLSServer()
	require.NoError(t, err)
	defer srv.Close()

	cl, err := srv.NewClient(auth.TestUser(user.GetName()))
	require.NoError(t, err)

	// Register two U2F devices
	deviceNames := []string{"device-a", "device-b"}
	for _, deviceName := range deviceNames {
		mockDev, err := mocku2f.Create()
		require.NoError(t, err)

		addStream, err := cl.AddMFADevice(ctx)
		require.NoError(t, err)

		require.NoError(t, addStream.Send(&proto.AddMFADeviceRequest{
			Request: &proto.AddMFADeviceRequest_Init{Init: &proto.AddMFADeviceRequestInit{
				DeviceName: deviceName,
				Type:       proto.AddMFADeviceRequestInit_U2F,
			}},
		}))

		// Get and respond to auth challenge (empty for first device)
		resp, err := addStream.Recv()
		require.NoError(t, err)
		require.NoError(t, addStream.Send(&proto.AddMFADeviceRequest{
			Request: &proto.AddMFADeviceRequest_ExistingMFAResponse{
				ExistingMFAResponse: &proto.MFAAuthenticateResponse{},
			},
		}))

		// Get U2F registration challenge
		resp, err = addStream.Recv()
		require.NoError(t, err)
		u2fRegChallenge := resp.GetNewMFARegisterChallenge().GetU2F()
		require.NotNil(t, u2fRegChallenge)

		regResp, err := mockDev.RegisterResponse(&u2flib.RegisterChallenge{
			Challenge: u2fRegChallenge.Challenge,
			AppID:     u2fRegChallenge.AppID,
		})
		require.NoError(t, err)

		require.NoError(t, addStream.Send(&proto.AddMFADeviceRequest{
			Request: &proto.AddMFADeviceRequest_NewMFARegisterResponse{
				NewMFARegisterResponse: &proto.MFARegisterResponse{
					Response: &proto.MFARegisterResponse_U2F{
						U2F: &proto.U2FRegisterResponse{
							RegistrationData: regResp.RegistrationData,
							ClientData:       regResp.ClientData,
						},
					},
				},
			},
		}))

		resp, err = addStream.Recv()
		require.NoError(t, err)
		require.NoError(t, addStream.CloseSend())
	}

	// Verify both devices are registered
	devicesResp, err := cl.GetMFADevices(ctx, &proto.GetMFADevicesRequest{})
	require.NoError(t, err)
	require.Equal(t, 2, len(devicesResp.Devices), "Should have 2 U2F devices registered")

	// Document the expected behavior for multi-device authentication:
	// When a user with 2 U2F devices logs in, the expected flow is:
	// 1. Server generates authentication challenges for BOTH devices
	// 2. Server sends both challenges to the client
	// 3. Client receives challenges for all registered devices
	// 4. User sees prompts to tap any of their registered devices
	// 5. User taps one device
	// 6. Device responds with signature
	// 7. Server identifies which device responded using the KeyHandle
	// 8. Authentication succeeds
	//
	// BUGGY BEHAVIOR (the bug being tested):
	// 1. Server only generates a challenge for the first device (due to early return)
	// 2. Client receives only one challenge
	// 3. User cannot use other registered devices
	// 4. Authentication is limited to a single device

	t.Logf("Two U2F devices successfully registered. " +
		"The multi-device U2F bug manifests during login when the server " +
		"creates only a single challenge instead of one for each device. " +
		"This is caused by an early return in the U2FSignRequest method.")
}

// testMultiDeviceChallengeSeparation verifies device challenge isolation.
func testMultiDeviceChallengeSeparation(t *testing.T) {
	ctx := context.Background()
	clock := clockwork.NewFakeClock()

	as, err := auth.NewTestAuthServer(auth.TestAuthServerConfig{
		Dir:   t.TempDir(),
		Clock: clock,
	})
	require.NoError(t, err)
	defer as.Close()

	// Enable U2F support
	authPref, err := services.NewAuthPreference(types.AuthPreferenceSpecV2{
		Type: teleport.Local,
		U2F: &types.U2F{
			AppID:  "teleport",
			Facets: []string{"teleport"},
		},
	})
	require.NoError(t, err)
	err = as.AuthServer.SetAuthPreference(authPref)
	require.NoError(t, err)

	// Create user and register devices
	user, _, err := auth.CreateUserAndRole(as.AuthServer, "test-user-isolation", []string{"role"})
	require.NoError(t, err)

	srv, err := as.NewTestTLSServer()
	require.NoError(t, err)
	defer srv.Close()

	cl, err := srv.NewClient(auth.TestUser(user.GetName()))
	require.NoError(t, err)

	// Register two devices
	keyHandles := make(map[string][]byte)
	for i, deviceName := range []string{"device-1", "device-2"} {
		mockDev, err := mocku2f.Create()
		require.NoError(t, err)
		keyHandles[deviceName] = mockDev.KeyHandle

		addStream, err := cl.AddMFADevice(ctx)
		require.NoError(t, err)

		require.NoError(t, addStream.Send(&proto.AddMFADeviceRequest{
			Request: &proto.AddMFADeviceRequest_Init{Init: &proto.AddMFADeviceRequestInit{
				DeviceName: deviceName,
				Type:       proto.AddMFADeviceRequestInit_U2F,
			}},
		}))

		resp, err := addStream.Recv()
		require.NoError(t, err)
		require.NoError(t, addStream.Send(&proto.AddMFADeviceRequest{
			Request: &proto.AddMFADeviceRequest_ExistingMFAResponse{
				ExistingMFAResponse: &proto.MFAAuthenticateResponse{},
			},
		}))

		resp, err = addStream.Recv()
		require.NoError(t, err)
		u2fRegChallenge := resp.GetNewMFARegisterChallenge().GetU2F()
		require.NotNil(t, u2fRegChallenge)

		regResp, err := mockDev.RegisterResponse(&u2flib.RegisterChallenge{
			Challenge: u2fRegChallenge.Challenge,
			AppID:     u2fRegChallenge.AppID,
		})
		require.NoError(t, err)

		require.NoError(t, addStream.Send(&proto.AddMFADeviceRequest{
			Request: &proto.AddMFADeviceRequest_NewMFARegisterResponse{
				NewMFARegisterResponse: &proto.MFARegisterResponse{
					Response: &proto.MFARegisterResponse_U2F{
						U2F: &proto.U2FRegisterResponse{
							RegistrationData: regResp.RegistrationData,
							ClientData:       regResp.ClientData,
						},
					},
				},
			},
		}))

		resp, err = addStream.Recv()
		require.NoError(t, err)
		require.NoError(t, addStream.CloseSend())

		if i == 0 {
			kh := base64.URLEncoding.WithPadding(base64.NoPadding).EncodeToString(mockDev.KeyHandle)
			t.Logf("Registered device %q with KeyHandle length %d (base64: %s...)",
				deviceName, len(mockDev.KeyHandle), kh[:20])
		}
	}

	// Verify devices are registered
	devicesResp, err := cl.GetMFADevices(ctx, &proto.GetMFADevicesRequest{})
	require.NoError(t, err)
	require.Equal(t, 2, len(devicesResp.Devices), "Should have 2 registered devices")

	// Verify key handles are different (this is critical for device separation)
	var keyHandleCount int
	seenKeyHandles := make(map[string]bool)
	for _, dev := range devicesResp.Devices {
		u2fDev := dev.GetU2F()
		if u2fDev != nil {
			kh := base64.URLEncoding.WithPadding(base64.NoPadding).EncodeToString(u2fDev.KeyHandle)
			seenKeyHandles[kh] = true
			keyHandleCount++
		}
	}

	if keyHandleCount != len(seenKeyHandles) {
		t.Error("BUG: Duplicate key handles found - devices are not properly isolated!")
	}
	require.Equal(t, 2, keyHandleCount, "Should have 2 U2F devices")
	require.Equal(t, 2, len(seenKeyHandles), "All key handles should be unique")

	t.Logf("ISOLATION TEST PASSED: Both devices have unique KeyHandles, " +
		"which ensures they can be properly distinguished during authentication. " +
		"However, the multi-device U2F bug prevents these devices from all being " +
		"challenged during login, effectively limiting authentication to one device.")
}

// Utility function to close the test auth server properly
func (a *auth.TestAuthServer) Close() {
	if a.AuthServer != nil {
		a.AuthServer.Close()
	}
}

